// Approach 1: Extending Thread
class CounterThread extends Thread {
    private String label;

    public CounterThread(String label) {
        this.label = label;
    }

    @Override
    public void run() {
        for (int i = 1; i <= 3; i++) {
            System.out.println(label + ": " + i);
        }
    }
}

// Approach 2: Implementing Runnable
class CounterTask implements Runnable {
    private String label;

    public CounterTask(String label) {
        this.label = label;
    }

    @Override
    public void run() {
        for (int i = 1; i <= 3; i++) {
            System.out.println(label + ": " + i);
        }
    }
}

public class ThreadCreation {
    public static void main(String[] args) {
        // Using Thread subclass
        CounterThread t1 = new CounterThread("ThreadClass");
        t1.start();

        // Using Runnable
        Thread t2 = new Thread(new CounterTask("Runnable"));
        t2.start();

        // Using lambda (since Runnable is a functional interface)
        Thread t3 = new Thread(() -> {
            for (int i = 1; i <= 3; i++) {
                System.out.println("Lambda: " + i);
            }
        });
        t3.start();
    }
}

public class ThreadLifecycle {
    public static void main(String[] args) throws InterruptedException {
        Thread worker = new Thread(() -> {
            System.out.println("Worker: started");
            try {
                Thread.sleep(2000);
            } catch (InterruptedException e) {
                System.out.println("Worker: interrupted");
            }
            System.out.println("Worker: finished");
        }, "Worker-Thread");

        System.out.println("State after creation: " + worker.getState());    // NEW

        worker.start();
        System.out.println("State after start: " + worker.getState());       // RUNNABLE

        Thread.sleep(500);
        System.out.println("State during sleep: " + worker.getState());      // TIMED_WAITING

        System.out.println("Main: waiting for worker...");
        worker.join(); // Block until worker finishes
        System.out.println("State after join: " + worker.getState());        // TERMINATED

        System.out.println("Main: worker is done, continuing.");
    }
}

