public class RaceConditionDemo {
    public static void main(String[] args) throws InterruptedException {
        Counter counter = new Counter();

        Thread t1 = new Thread(() -> {
            for (int i = 0; i < 10000; i++) {
                counter.increment();
            }
        });

        Thread t2 = new Thread(() -> {
            for (int i = 0; i < 10000; i++) {
                counter.increment();
            }
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Expected: 20000");
        System.out.println("Actual: " + counter.getCount());
        // Without synchronized: often less than 20000 (race condition)
        // With synchronized: always 20000
    }
}

public class DeadlockDemo {
    private static final Object LOCK_A = new Object();
    private static final Object LOCK_B = new Object();

    public static void main(String[] args) {
        Thread t1 = new Thread(() -> {
            synchronized (LOCK_A) {
                System.out.println("Thread-1: acquired LOCK_A");
                try { Thread.sleep(100); } catch (InterruptedException e) {}
                System.out.println("Thread-1: waiting for LOCK_B...");
                synchronized (LOCK_B) {
                    System.out.println("Thread-1: acquired LOCK_B");
                }
            }
        }, "Thread-1");

        Thread t2 = new Thread(() -> {
            synchronized (LOCK_B) {
                System.out.println("Thread-2: acquired LOCK_B");
                try { Thread.sleep(100); } catch (InterruptedException e) {}
                System.out.println("Thread-2: waiting for LOCK_A...");
                synchronized (LOCK_A) {
                    System.out.println("Thread-2: acquired LOCK_A");
                }
            }
        }, "Thread-2");

        t1.start();
        t2.start();

        // This program will hang forever due to deadlock.
        // Thread-1 holds LOCK_A, needs LOCK_B.
        // Thread-2 holds LOCK_B, needs LOCK_A.
        // Neither can proceed.
    }
}

class MessageQueue {
    private String message;
    private boolean hasMessage = false;

    public synchronized void put(String msg) throws InterruptedException {
        while (hasMessage) {
            wait();
        }
        this.message = msg;
        this.hasMessage = true;
        System.out.println("Produced: " + msg);
        notify();
    }

    public synchronized String take() throws InterruptedException {
        while (!hasMessage) {
            wait();
        }
        hasMessage = false;
        System.out.println("Consumed: " + message);
        notify();
        return message;
    }
}

public class ProducerConsumer {
    public static void main(String[] args) {
        MessageQueue queue = new MessageQueue();

        Thread producer = new Thread(() -> {
            String[] messages = {"Hello", "World", "Java", "Done"};
            try {
                for (String msg : messages) {
                    queue.put(msg);
                    Thread.sleep(500);
                }
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        });

        Thread consumer = new Thread(() -> {
            try {
                for (int i = 0; i < 4; i++) {
                    queue.take();
                    Thread.sleep(800);
                }
            } catch (InterruptedException e) {
                e.printStackTrace();
            }
        });

        producer.start();
        consumer.start();
    }
}

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class ThreadPoolDemo {
    public static void main(String[] args) throws InterruptedException {
        ExecutorService pool = Executors.newFixedThreadPool(3);

        for (int i = 1; i <= 6; i++) {
            int taskId = i;
            pool.submit(() -> {
                String threadName = Thread.currentThread().getName();
                System.out.println("Task " + taskId + " started on " + threadName);
                try {
                    Thread.sleep(1000);
                } catch (InterruptedException e) {
                    Thread.currentThread().interrupt();
                }
                System.out.println("Task " + taskId + " completed on " + threadName);
            });
        }

        pool.shutdown();
        boolean finished = pool.awaitTermination(10, TimeUnit.SECONDS);
        System.out.println("All tasks finished: " + finished);
    }
}

public class VolatileDemo {
    private static volatile boolean running = true;

    public static void main(String[] args) throws InterruptedException {
        Thread worker = new Thread(() -> {
            int count = 0;
            while (running) {
                count++;
            }
            System.out.println("Worker stopped after " + count + " iterations.");
        });

        worker.start();
        Thread.sleep(100); // Let worker run for 100ms
        running = false;    // Signal worker to stop
        System.out.println("Main: set running to false");
        worker.join();
        System.out.println("Main: worker has stopped.");
    }
}

